const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];

  // Get LLM output (format: "domain.com|City, State")
  const llmOutput = item.json.text || item.json.output || '';

  let specificDomain = '';
  let parentDomain = '';
  let location = '';

  if (llmOutput && llmOutput.includes('|')) {
    const parts = llmOutput.split('|');
    specificDomain = parts[0].trim().toLowerCase().replace(/https?:\/\//g, '').replace(/www\./g, '');
    location = parts[1].trim();
  }

  // Get the original hotel data
  const hotelData = $('Read Hotel Names').all()[i]?.json || {};
  const hotelName = hotelData['Hotel name'] || '';

  // Extract parent brand domain from hotel name
  if (hotelName.toLowerCase().includes('holiday inn') || hotelName.toLowerCase().includes('ihg')) {
    parentDomain = 'ihg.com';
  } else if (hotelName.toLowerCase().includes('marriott')) {
    parentDomain = 'marriott.com';
  } else if (hotelName.toLowerCase().includes('hilton')) {
    parentDomain = 'hilton.com';
  } else if (hotelName.toLowerCase().includes('hyatt')) {
    parentDomain = 'hyatt.com';
  } else if (hotelName.toLowerCase().includes('hampton')) {
    parentDomain = 'hilton.com';
  } else if (hotelName.toLowerCase().includes('courtyard') || hotelName.toLowerCase().includes('residence inn')) {
    parentDomain = 'marriott.com';
  }

  // Use BOTH domains in search - Apollo will match if either exists
  const domainsToSearch = [];
  if (specificDomain) domainsToSearch.push(specificDomain);
  if (parentDomain && parentDomain !== specificDomain) domainsToSearch.push(parentDomain);

  // If no domains found, just use location-based search
  if (domainsToSearch.length === 0) {
    console.log(` No domain found for: ${hotelName}, using location-only search`);
  }

  // Create Apollo request body
  const apolloRequestBody = {
    person_locations: [location],
    person_titles: [
      "General Manager",
      "Assistant General Manager",
      "Director of Housekeeping",
      "Assistant Director of Housekeeping"
    ],
    per_page: 10,
    page: 1
  };

  // Add domains only if we have them
  if (domainsToSearch.length > 0) {
    apolloRequestBody.organization_domains = domainsToSearch;
  }

  results.push({
    json: {
      sr_no: hotelData['Sr. no.'] || '',
      hotel_name: hotelName,
      location: location,
      company_domain: specificDomain || parentDomain || '',

      apollo_request_body: apolloRequestBody,

      // Debug
      specific_domain: specificDomain,
      parent_domain: parentDomain,
      search_strategy: domainsToSearch.length > 0 ? 'domain+location' : 'location-only',
      raw_llm_output: llmOutput
    }
  });
}

return results;

const items = $input.all();
const contacts = [];

const hotelDataItems = $('Parse Domain Output').all();

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const searchResults = item.json.people || [];

  const hotelData = hotelDataItems[i]?.json || {};

  console.log(`\n=== Hotel ${i}: ${hotelData.hotel_name} ===`);
  console.log(`Found ${searchResults.length} contacts`);

  for (const person of searchResults) {
    // Log what we're getting from Apollo
    console.log(`\nPerson data:`, JSON.stringify(person, null, 2));

    // Extract phone numbers
    const phones = person.phone_numbers || [];
    const directPhone = person.direct_phone || person.corporate_phone || '';
    const workPhone = phones.find(p => p.type === 'work')?.sanitized_number || directPhone;

    // Extract name fields - CHECK ALL POSSIBLE FIELDS
    const firstName = person.first_name || person.firstName || '';
    const lastName = person.last_name || person.lastName || person.last_name_obfuscated || '';
    const fullName = person.name || person.full_name || `${firstName} ${lastName}`.trim() || '';

    // Extract other fields
    const email = person.email || '';
    const linkedinUrl = person.linkedin_url || person.linkedinUrl || '';
    const jobTitle = person.title || person.job_title || '';
    const companyName = person.organization?.name || person.organization_name || person.company || '';

    console.log(`Extracted: ${firstName} ${lastName} | ${jobTitle} | LinkedIn: ${linkedinUrl ? 'YES' : 'NO'}`);

    contacts.push({
      json: {
        // Hotel data
        sr_no: hotelData.sr_no || '',
        hotel_name: hotelData.hotel_name || '',
        location: hotelData.location || '',
        company_domain: hotelData.company_domain || '',

        // Apollo ID
        apollo_id: person.id || '',

        // Contact details
        first_name: firstName,
        last_name: lastName,
        full_name: fullName,
        job_title: jobTitle,
        linkedin_url: linkedinUrl,
        company_name: companyName,
        email: email,
        phone: workPhone,

        // Debug
        _raw_person: person
      }
    });
  }

  if (searchResults.length === 0) {
    console.log(`❌ No contacts found for: ${hotelData.hotel_name}`);
    contacts.push({
      json: {
        sr_no: hotelData.sr_no || '',
        hotel_name: hotelData.hotel_name || '',
        location: hotelData.location || '',
        company_domain: hotelData.company_domain || '',
        error: 'No contacts found'
      }
    });
  }
}

console.log(`\n✅ Total contacts extracted: ${contacts.length}`);
return contacts;

const items = $input.all();
const enriched = [];

// Get the data from Parse Search Results to retrieve hotel info
const searchResultsItems = $('Parse Search Results').all();

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const person = item.json.person || item.json;

  // Get corresponding hotel data from Parse Search Results
  const originalData = searchResultsItems[i]?.json || {};

  // Extract phone numbers
  const phones = person.phone_numbers || [];
  const workPhone = phones.find(p => p.type === 'work')?.sanitized_number || '';
  const mobilePhone = phones.find(p => p.type === 'mobile')?.sanitized_number || 
                      phones.find(p => p.type === 'home')?.sanitized_number || '';

  // Extract personal email
  const personalEmails = person.personal_emails || [];
  const personalEmail = personalEmails[0] || '';

  enriched.push({
    json: {
      // CRITICAL: Preserve hotel data from Parse Search Results
      sr_no: originalData.sr_no || '',
      hotel_name: originalData.hotel_name || '',
      hotel_city: originalData.hotel_city || '',
      hotel_state: originalData.hotel_state || '',
      location: originalData.location || '',
      company_domain: originalData.company_domain || '',

      // Contact details
      first_name: person.first_name || originalData.first_name || '',
      last_name: person.last_name || originalData.last_name || '',
      full_name: person.name || originalData.full_name || '',
      job_title: person.title || originalData.job_title || '',

      // Contact info (enriched)
      email: person.email || '',
      email_status: person.email_status || '',
      phone: workPhone,
      personal_email: personalEmail,
      mobile: mobilePhone,

      // Professional info
      linkedin_url: person.linkedin_url || originalData.linkedin_url || '',
      company_name: person.organization?.name || '',

      // Metadata
      enriched: true,
      has_email: !!(person.email),
      has_phone: !!(workPhone),
      has_personal_email: !!(personalEmail),
      has_mobile: !!(mobilePhone)
    }
  });
}

return enriched;

const items = $input.all();
const formatted = [];

for (const item of items) {
  const data = item.json;

  // Clean phone format
  const cleanPhone = (phone) => {
    if (!phone) return '';
    return `'${phone.toString().replace(/[^\d\s\+\-\(\)]/g, '').trim()}`;
  };

  formatted.push({
    json: {
      // MATCHING COLUMN (with dot!)
      'Sr. no.': data.sr_no || '',

      // UPDATE ONLY THESE COLUMNS
      'FIRST NAME ': data.first_name || '',
      'Last Name': data.last_name || '',
      ' Full Name': data.full_name || '',
      'Location': data.location || '',
      'Job Title': data.job_title || '',
      'Company Domain': data.company_domain || '',
      'Exact Hotel Name': data.hotel_name || '',
      'Google Maps Link': '',
      'LinkedIn Profile': data.linkedin_url || '',
      'Company Name': data.company_name || '',
      'Email': data.email || '',
      'Phone': cleanPhone(data.phone),
      'Personal Email': data.personal_email || '',
      'Personal Mobile Phone': cleanPhone(data.mobile)
    }
  });
}

return formatted;
